parameters.jsCode:
// Validate and enrich incoming exam data
const body = $input.first().json.body || $input.first().json;

const required = ['studentEmail', 'examTitle', 'score', 'attemptId'];
const missing = required.filter(f => !body[f]);

if (missing.length > 0) {
  throw new Error('Missing required fields: ' + missing.join(', '));
}

const score = parseFloat(body.score) || 0;
const trustScore = parseFloat(body.trustScore) || 100;
const passed = score >= 60;

return [{
  json: {
    ...body,
    score,
    trustScore,
    passed,
    grade: score >= 90 ? 'A' : score >= 80 ? 'B' : score >= 70 ? 'C' : score >= 60 ? 'D' : 'F',
    riskLevel: trustScore < 30 ? 'HIGH' : trustScore < 60 ? 'MEDIUM' : 'LOW',
    processedAt: new Date().toISOString(),
    notificationId: 'notif_' + Date.now()
  }
}];

// Log high-risk attempt
const data = $input.first().json;
console.log('[ALERT] HIGH RISK ATTEMPT DETECTED');
console.log('Student:', data.studentEmail);
console.log('Exam:', data.examTitle);
console.log('Trust Score:', data.trustScore);
console.log('Risk Level:', data.riskLevel);

return [{
  json: {
    ...data,
    alertSent: true,
    alertTime: new Date().toISOString(),
    message: `[HIGH RISK] Student ${data.studentEmail} - TrustScore: ${data.trustScore}%`
  }
}];

// Generate certificate data
const data = $input.first().json;
const certCode = 'CERT-' + data.examTitle.substring(0,3).toUpperCase() + '-' + Date.now().toString(36).toUpperCase();

return [{
  json: {
    ...data,
    certificateCode: certCode,
    certificateUrl: `http://localhost:3001/certificates/verify/${certCode}`,
    issuedAt: new Date().toISOString(),
    emailSubject: `🎓 Поздравляем! Сертификат: ${data.examTitle}`,
    emailBody: `Здравствуйте, ${data.studentName || data.studentEmail}!\n\n✅ Вы успешно сдали экзамен: ${data.examTitle}\n📊 Результат: ${data.score}% (Оценка: ${data.grade})\n🛡️ Trust Score: ${data.trustScore}%\n🏆 Сертификат: ${certCode}\n🔗 Проверить: http://localhost:3001/certificates/verify/${certCode}\n\nСпасибо,\nКоманда ProctoLearn`
  }
}];

// Generate failure notification
const data = $input.first().json;

return [{
  json: {
    ...data,
    emailSubject: `❌ Результат экзамена: ${data.examTitle}`,
    emailBody: `Здравствуйте, ${data.studentName || data.studentEmail}!

К сожалению, вы не сдали экзамен.

📚 Экзамен: ${data.examTitle}
📊 Результат: ${data.score}% (нужно минимум 60%)
📉 Оценка: ${data.grade}

Не расстраивайтесь! Вы можете попробовать ещё раз.

Спасибо,
Команда ProctoLearn`,
    retryAllowed: true
  }
}];

// Aggregate all data and create final audit log
const data = $input.first().json;

const auditLog = {
  timestamp: new Date().toISOString(),
  notificationId: data.notificationId,
  attemptId: data.attemptId,
  student: data.studentEmail,
  exam: data.examTitle,
  score: data.score,
  grade: data.grade,
  passed: data.passed,
  trustScore: data.trustScore,
  riskLevel: data.riskLevel,
  alertSent: data.alertSent || false,
  certificateCode: data.certificateCode || null,
  status: 'PROCESSED'
};

console.log('AUDIT LOG:', JSON.stringify(auditLog, null, 2));

return [{ json: { ...data, auditLog, finalStatus: 'SUCCESS' } }];

